mapper.select:
SELECT id, room_type, name, created_by, created_at
FROM msg_rooms
WHERE id = #{id}

SELECT r.id, r.room_type, r.name, r.created_by, r.created_at
FROM msg_rooms r
WHERE r.room_type = 'DIRECT'
  AND EXISTS (
      SELECT 1 FROM msg_room_members m1
      WHERE m1.room_id = r.id AND m1.user_id = #{userId1}
  )
  AND EXISTS (
      SELECT 1 FROM msg_room_members m2
      WHERE m2.room_id = r.id AND m2.user_id = #{userId2}
  )
  AND (
      SELECT COUNT(*) FROM msg_room_members m3
      WHERE m3.room_id = r.id
  ) = 2
LIMIT 1

SELECT EXISTS (
    SELECT 1 FROM msg_room_members
    WHERE room_id = #{roomId} AND user_id = #{userId}
)

mapper.update:
UPDATE msg_room_members
SET last_read_at = NOW()
WHERE room_id = #{roomId} AND user_id = #{userId}

mapper.select:
SELECT u.fcf_user_id
FROM msg_room_members rm
JOIN msg_users u ON u.id = rm.user_id
WHERE rm.room_id = #{roomId}
  AND rm.user_id != #{excludeUserId}
  AND u.fcf_user_id IS NOT NULL
